INSERT INTO mi_checklist_questions (checklist_id, text, requirement, hint, sort_order) VALUES
(1, 'Проведено ли плановое техническое обслуживание трубопровода в установленные сроки?', 'Федеральные нормы и правила в области промышленной безопасности «Правила безопасности для объектов, использующих сжиженные углеводородные газы» (Приказ Ростехнадзора № 521)', 'Проверьте журнал технического обслуживания — запись должна быть не старше 30 дней.', 0),
(1, 'Наличие и исправность запорной арматуры на всех узлах трубопровода?', 'ГОСТ 32569-2013. Трубопроводы технологические. Требования к устройству и эксплуатации.', 'Осмотрите каждый кран и задвижку — отсутствие течей, свободное открытие/закрытие.', 1),
(1, 'Проведена ли проверка катодной защиты в текущем квартале?', 'ГОСТ Р 51164-98. Трубопроводы стальные магистральные. Защита от коррозии.', 'Акт измерения потенциала трубопровода должен быть в наличии.', 2),
(1, 'Установлены ли знаки и предупредительные таблички на трассе трубопровода?', 'РД 39-132-94 «Правила по эксплуатации, ревизии, ремонту и отбраковке нефтепромысловых трубопроводов»', 'Знаки устанавливаются через каждые 500 м, у пересечений дорог и водоёмов.', 3),
(1, 'Проведён ли инструктаж персонала, обслуживающего трубопровод?', 'ФЗ №116 «О промышленной безопасности опасных производственных объектов»', 'Отметка о проведении инструктажа — в журнале инструктажей по ОТ.', 4),
(2, 'Имеется ли паспорт сосуда с актуальными записями о техническом освидетельствовании?', 'ФНП «Правила промышленной безопасности при использовании оборудования, работающего под избыточным давлением» (Приказ Ростехнадзора № 536)', 'Паспорт должен храниться у ответственного за безопасную эксплуатацию.', 0),
(2, 'Не превышен ли допустимый срок до следующего технического освидетельствования?', 'Приказ Ростехнадзора № 536, п. 401 — наружный осмотр 1 раз в 2 года, гидравлические испытания — 1 раз в 8 лет.', 'Дата следующего освидетельствования указана в паспорте сосуда.', 1),
(2, 'Исправны ли предохранительные клапаны и манометры?', 'ГОСТ 12.2.085-2002. Сосуды, работающие под давлением. Предохранительные клапаны.', 'Манометр — класс точности не ниже 2.5, пломба или клеймо с датой поверки.', 2),
(3, 'Проведено ли техническое освидетельствование крана в установленные сроки?', 'ФНП «Правила безопасности опасных производственных объектов, на которых используются подъёмные сооружения» (Приказ Ростехнадзора № 461)', 'Частичное освидетельствование — 1 раз в год, полное — 1 раз в 3 года.', 0),
(3, 'Наличие удостоверения у крановщика/стропальщика?', 'Приказ Ростехнадзора № 461, п. 159 — требования к квалификации персонала.', 'Удостоверение должно быть действующим, с актуальной отметкой о проверке знаний.', 1),
(4, 'Обеспечены ли работники средствами индивидуальной защиты?', 'Приказ Минтруда России № 767н «Об утверждении Единых типовых норм выдачи СИЗ»', 'СИЗ выдаются по нормам, карточки учёта хранятся в отделе охраны труда.', 0),
(4, 'Проведён ли специальная оценка условий труда (СОУТ)?', 'Федеральный закон № 426-ФЗ «О специальной оценке условий труда»', 'СОУТ проводится не реже 1 раза в 5 лет. Карты СОУТ должны быть на рабочих местах.', 1),
(4, 'Оформлены ли инструкции по охране труда по каждой профессии?', 'Приказ Минтруда России № 772н «Об утверждении основных требований к порядку разработки инструкций по охране труда»', 'Инструкции пересматриваются не реже 1 раза в 5 лет или при изменении условий труда.', 2),
(5, 'Проведена ли своевременная перезарядка огнетушителей?', 'ППР в РФ (Постановление Правительства № 1479), п. 60 — проверка огнетушителей не реже 1 раза в год.', 'На огнетушителе должна быть бирка с датой последней проверки и перезарядки.', 0),
(5, 'Установлены ли огнетушители на видных и доступных местах?', 'СП 9.13130.2009. Техника пожарная. Огнетушители. Требования к эксплуатации.', 'Огнетушители вешаются на высоте не более 1.5 м от уровня пола, знаки — по ГОСТ 12.4.026.', 1),
(5, 'Обозначены ли пути эвакуации и аварийные выходы?', 'ГОСТ 12.2.143-2009. Системы фотолюминесцентные эвакуационные.', 'Знаки на путях эвакуации должны быть освещены или фотолюминесцентными.', 2),
(6, 'Ведётся ли журнал учёта отходов производства и потребления?', 'Федеральный закон № 89-ФЗ «Об отходах производства и потребления», Приказ Минприроды № 1028', 'Журнал заполняется ежеквартально. Форма утверждена Приказом Минприроды № 1028.', 0),
(6, 'Заключён ли договор со специализированной организацией на вывоз отходов?', 'ФЗ № 89-ФЗ, ст. 13 — требования к обращению с отходами.', 'Договор и лицензия исполнителя должны храниться в отделе экологии.', 1),
(7, 'Пройден ли технический осмотр транспортного средства?', 'Федеральный закон № 170-ФЗ «О техническом осмотре транспортных средств»', 'Диагностическая карта должна быть действующей. Срок ТО зависит от категории ТС.', 0),
(7, 'Проведён ли предрейсовый медицинский осмотр водителя?', 'Приказ Минздрава России № 834н «О медицинских осмотрах водителей»', 'Отметка о прохождении медосмотра — в путевом листе.', 1),
(8, 'Разработана ли программа производственного контроля?', 'Федеральный закон № 52-ФЗ «О санитарно-эпидемиологическом благополучии населения», ст. 32', 'Программа ПК разрабатывается юридическим лицом самостоятельно и согласуется с Роспотребнадзором.', 0),
(8, 'Проведены ли лабораторные исследования в рамках ПК?', 'СП 1.1.1058-01. Организация и проведение производственного контроля.', 'Протоколы испытаний должны быть в наличии за текущий период.', 1),
(9, 'Разработан ли паспорт безопасности объекта?', 'Постановление Правительства РФ № 1995 «Об утверждении требований к антитеррористической защищённости объектов»', 'Паспорт безопасности разрабатывается и согласуется с Росгвардией и ФСБ.', 0),
(9, 'Проведён ли инструктаж персонала по действиям при угрозе теракта?', 'Постановление Правительства РФ № 1438, раздел о подготовке персонала.', 'Инструктаж проводится не реже 1 раза в год, записи — в журнале инструктажей.', 1),
(10, 'Все ли первичные документы оформлены по установленным формам?', 'Федеральный закон № 402-ФЗ «О бухгалтерском учёте», ст. 9 — требования к первичным документам.', 'Обязательные реквизиты: наименование, дата, организация, содержание, подписи.', 0),
(10, 'Соблюдаются ли сроки сдачи первичных документов в бухгалтерию?', 'Учётная политика организации — график документооборота.', 'График документооборота утверждается приказом руководителя.', 1),
(11, 'Назначен ли ответственный за обработку персональных данных?', 'Федеральный закон № 152-ФЗ «О персональных данных», ст. 22.1', 'Приказ о назначении ответственного должен быть в наличии.', 0),
(11, 'Получены ли согласия субъектов ПД на их обработку?', 'ФЗ № 152-ФЗ, ст. 9 — требования к согласию субъекта ПД.', 'Форма согласия должна содержать все обязательные элементы по ст. 9 ФЗ-152.', 1),
(11, 'Проведена ли оценка уровня защищённости информационной системы ПД?', 'Постановление Правительства РФ № 1119, ФЗ № 152-ФЗ', 'Акт классификации ИСПДн и технический паспорт должны быть в наличии.', 2);
